noncompliant:
void fn ( void )
{
  DoSomething ( );
  asm ( "NOP" ); // Noncompliant, asm mixed with C/C++ statements
  DoSomething ( );
}

int calculate(int x)
{
    int result = x * 2;
    __asm__ volatile ("nop"); // Noncompliant, inline assembly mixed with C statements
    return result;
}

void process_data(void)
{
    init_data();
    asm("mov eax, 0"); // Noncompliant, assembly mixed with function calls
    finalize_data();
}

compliant:
void Delay ( void )
{
  asm ( "NOP" ); // Compliant, asm not mixed with C/C++ statements
}

void fn ( void )
{
  DoSomething ( );
  Delay ( ); // Compliant, Assembler is encapsulated
  DoSomething ( );
}

void low_level_operation(void)
{
    __asm__ volatile (
        "mov eax, 0\n\t"
        "cpuid\n\t"
        : : : "eax", "ebx", "ecx", "edx"
    ); // Compliant, function contains only assembly
}

static inline void memory_barrier(void)
{
    asm volatile("" : : : "memory"); // Compliant, encapsulated in dedicated function
}
